// ❌ コンパイルエラーのパターン
class Parent {
    Parent(String msg) { // 引数ありコンストラクタのみ
        System.out.println(msg);
    }
    // → デフォルトコンストラクタ Parent() は自動生成されない！
}

class Child extends Parent {
    Child() {
        // super()が暗黙的に挿入される
        // → Parent()がないのでコンパイルエラー！
    }
}

// ✅ 修正方法1: 明示的にsuper(引数)を呼ぶ
class Child extends Parent {
    Child() {
        super("hello"); // 親の引数ありコンストラクタを呼ぶ
    }
}

// ✅ 修正方法2: 親に引数なしコンストラクタを追加
