// 抽象クラス
// Shapeクラスの定義
abstract class Shape {
    String color;

    Shape(String color) {
        this.color = color;
    }

    // 抽象メソッド（処理なし、子クラスで実装を強制）
    abstract double area();

    // 通常メソッド（共通処理はここに書ける）
    // displayメソッドの定義
    void display() {
        System.out.println(color + "の図形、面積: " + area());
    }
}

// 子クラスで抽象メソッドを実装
// Circleクラスの定義
class Circle extends Shape {
    double radius;

    Circle(String color, double radius) {
        super(color);
        this.radius = radius;
    }
    @Override
    // areaメソッドの定義
    double area() {
        return Math.PI * radius * radius;
    }
}

// Rectangleクラスの定義
class Rectangle extends Shape {
    double w, h;

    Rectangle(String color, double w, double h) {
        super(color);
        this.w = w;
        this.h = h;
    }
    @Override
    double area() {
        return w * h;
    }
}

// Shape s = new Shape("赤"); // コンパイルエラー！抽象クラスはnewできない
Shape s = new Circle("赤", 5.0);
s.display(); // 赤の図形、面積: 78.539...

