// Greeterインターフェースの定義
interface Greeter {
    // 抽象メソッド（実装必須）
    String getName();

    // defaultメソッド（デフォルト実装あり、オーバーライド任意）
    default void greet() {
        System.out.println("こんにちは、" + getName() + "さん");
    }

    // staticメソッド（インターフェース名で呼ぶ）
    // infoメソッドの定義
    static void info() {
        System.out.println("Greeterインターフェース v1.0");
    }
}

// Userクラスの定義
class User implements Greeter {
    private String name;
    User(String name) { this.name = name; }

    @Override
    // getNameメソッドの定義
    public String getName() { return name; }
    // greet() はdefault実装をそのまま使える
}

User u = new User("太郎");
u.greet();       // こんにちは、太郎さん（default実装）
Greeter.info();  // Greeterインターフェース v1.0（static呼び出し）

// defaultメソッドをオーバーライドすることも可能
// VIPUserクラスの定義
class VIPUser implements Greeter {
    @Override public String getName() { return "VIP"; }
    @Override public void greet() {
        System.out.println("特別なご挨拶: " + getName() + "様");
    }
}

