// 実用例: 型チェックしてからキャスト
static void handleAnimal(Animal animal) {
    // 条件分岐
    if (animal instanceof Dog) {
        Dog dog = (Dog) animal;
        dog.bark();
    // 別の条件をチェック
    } else if (animal instanceof Cat) {
        Cat cat = (Cat) animal;
