class Vehicle {
    void run() { System.out.println("走行中"); }
}
class Car extends Vehicle {
    void drift() { System.out.println("ドリフト!"); }
}

// アップキャスト（子→親）: 暗黙的、常に安全
Vehicle v = new Car();  // 自動（キャスト不要）
v.run();                // OK
// v.drift();           // コンパイルエラー！ Vehicle型にdrift()はない

// ダウンキャスト（親→子）: 明示的キャストが必要
Car c = (Car) v;        // キャスト（実体がCarなのでOK）
c.drift();              // OK → ドリフト!

// ⚠️ 実体と異なる型へのダウンキャストは実行時エラー
Vehicle v2 = new Vehicle(); // 実体はVehicle
// Car c2 = (Car) v2;      // ClassCastException!

// 安全なダウンキャスト: instanceofで先にチェック
if (v instanceof Car) {
    Car safeCar = (Car) v;  // 安全
    safeCar.drift();
}

