// Shapeクラスの定義
abstract class Shape {
    abstract double area();

    @Override
    // toStringメソッドの定義
    public String toString() {
        return getClass().getSimpleName() + ": 面積=" + area();
    }
}

// Circleクラスの定義
class Circle extends Shape {
    double r;
    Circle(double r) { this.r = r; }
    @Override double area() { return Math.PI * r * r; }
}

// Rectクラスの定義
class Rect extends Shape {
    double w, h;
    Rect(double w, double h) { this.w = w; this.h = h; }
    @Override double area() { return w * h; }
}

// ポリモーフィズム: 同じShape型で異なる動作
Shape[] shapes = {
    new Circle(5),
    new Rect(3, 4),
    new Circle(2)
};

// 拡張for文（コレクションの全要素を順番に処理）
for (Shape s : shapes) {
    System.out.println(s.toString());
    // Circle: 面積=78.539...
    // Rect: 面積=12.0
    // Circle: 面積=12.566...
}

// 面積の合計も簡単に計算
// 変数の宣言と初期化
double total = 0;
for (Shape s : shapes) total += s.area();
System.out.println("合計面積: " + total);

// Objectクラスの主要メソッド:
// toString() — 文字列表現を返す
// equals()   — 等価性を判定する
// hashCode() — ハッシュ値を返す

// Studentクラスの定義
class Student {
    String name;
    int id;

    Student(String name, int id) {
        this.name = name;
        this.id = id;
    }
    @Override
    // toStringメソッドの定義
    public String toString() {
        return "Student{name='" + name + "', id=" + id + "}";
    }
    @Override
    // equalsメソッドの定義
    public boolean equals(Object obj) {
        // 条件分岐
        if (this == obj) return true;
        if (!(obj instanceof Student)) return false;
        Student other = (Student) obj;
        return this.id == other.id &&
               this.name.equals(other.name);
    }
    @Override
    public int hashCode() {
        return name.hashCode() * 31 + id;
    }
}
Student s1 = new Student("太郎", 1);
Student s2 = new Student("太郎", 1);
System.out.println(s1.toString()); // Student{name='太郎', id=1}
System.out.println(s1.equals(s2)); // true
System.out.println(s1 == s2);      // false（参照比較）

